<template>
	<div class="info" v-infinite-scroll="load">
		<div>
			<h3 style="padding-bottom:10px">留个言吧</h3>
			<el-input placeholder="请输入昵称" v-model="nickname" maxlength="15" show-word-limit clearable class="nickname">
			</el-input>
			<el-input type="textarea" placeholder="各位看客老爷们留个言把" v-model="textarea" maxlength="100" show-word-limit>
			</el-input>
			<div class="info-footer">
				<div class="emoji" @click="emojiClick">
					<i class="icon-emoji"></i>
				</div>
				<div>
					<el-button type="primary" size="mini" @click="pushMessage">留言</el-button>
				</div>
			</div>
			<div v-if="dialog" style="position: relative;">
				<ul class="emojis-ul" style="background: #F4F5F5;">
					<li v-for="item in emojis" class="emojis-li" @click="pushEmojis(item)">{{item}}</li>
				</ul>
			</div>
		</div>
		<div style="margin-top:20px">
			<div style="display: flex;justify-content: space-between;">
				<h3 style="padding-bottom:10px">留言板</h3>
				<el-input placeholder="请输入关键字" v-model="keyword" style="width:20%">
					<el-button slot="append" icon="el-icon-search" type="primary" @click="keywordSearch"></el-button>
				</el-input>
			</div>
			<div>
				<ul>
					<li v-for="item in message">
						<div style="margin-top:30px">
							<div style="display: flex;">
								<img :src="defaultImg" alt="找不到图片" class="comment_img">
								<p style="width: 100%;padding-left: 15px;">
									<span style="color: #52A9D4">{{item.nickname}}</span>
									<span style="color: #ccc;margin-left: 10px;">({{item.add_time}})</span><br>
									<span v-html="item.content"></span>
								</p>
								<span class="huifu">回复</span>
							</div>
							<div>

							</div>
						</div>
					</li>
				</ul>
			</div>
		</div>
	</div>
</template>

<script>
	export default {
		components: {},
		data() {
			return {
				textarea: "",
				dialog: false,
				dialog2: false,
				emojis: ['😂', '🙏', '😄', '😏', '😇', '😅', '😌', '😘', '😍', '🤓', '😜', '😎', '😊', '😳', '🙄', '😱', '😒', '😔',
					'😷', '👿', '🤗', '😩', '😤', '😣', '😰', '😴', '😬', '😭', '👻', '👍', '✌️', '👉', '👀', '🐶', '🐷', '😹', '⚡️',
					'🔥', '🌈', '🍏', '⚽️', '❤️', '🇨🇳'
				],
				nickname: "",
				message: [],
				defaultImg: 'https://img1.doubanio.com/icon/user_normal.jpg',
				page: 1,
				total: 1,
				keyword: "",
			}
		},
		computed: {},
		created() {
			this.getMessage()
		},
		methods: {
			pushEmojis(item) {
				this.textarea = this.textarea + item
				this.dialog = false
			},
			emojiClick() {
				this.dialog = this.dialog ? false : true
			},
			//	填写留言板
			pushMessage() {
				if (this.nickname == "") return this.$message.error('请填写昵称');
				if (this.textarea == "") return this.$message.error('请填写留言');
				let list = {
					content: this.textarea,
					nickname: this.nickname,

				}
				this.$api.post('api?s=App.Table.Create', {
					model_name: 'message',
					data: JSON.stringify(list),
				}).then(() => {
					this.$message({
						showClose: true,
						message: '留言成功',
						type: 'success'
					});
					this.nickname = ""
					this.textarea = ""
					this.getMessage()
				})
			},
			//	获取留言数据
			getMessage() {
				this.$api.post('api?s=App.Table.FreeQuery', {
					model_name: 'message',
					where: '[["id", ">", "0"]]',
					page: this.page,
					perpage: 10
				}).then((resp) => {
					this.total = resp.data.data.total
					resp.data.data.list.forEach((item) => {
						this.message.push(item)
					})
				})
			},
			//	滚动条到底部加载数据
			load() {
				if (this.total / 10 < this.page) return
				this.page++
				this.getMessage()
			},
			//	关键字搜索
			keywordSearch(){
				this.$api.post('api?s=App.Table.FreeQuery', {
					model_name: 'message',
					page: 1,
					perpage: 10,
					logic:'or',
					where_nickname:'LIKE-'+this.keyword,
					where_add_time:'LIKE-'+this.keyword,
					where_content:'LIKE-'+this.keyword,
				}).then((resp) => {
					this.total = resp.data.data.total
					this.message = resp.data.data.list
				})
			}
		}
	}
</script>
<style scoped>
	.emojis-ul {
		width: 200px;
		height: 100%;
		border: 2px solid #e8e8e8;
	}

	.emojis-li {
		cursor: pointer;
		display: inline-block;
	}

	.emoji {
		display: flex;
		justify-content: center;
		align-items: center;
		width: 20px;
		height: 20px;
		padding: 5px 10px 0 10px;
	}

	.emoji:hover {
		cursor: pointer;
	}

	.icon-emoji {
		width: 40px;
		height: 100%;
		background: url('../../assets/icons/icon-emoji.svg') no-repeat;
		background-size: contain;
	}

	.info-footer {
		display: flex;
		justify-content: space-between;
		height: 30px;
		padding: 10px 10px 0 10px;
	}

	.nickname {
		width: 30%;
		margin-bottom: 20px;
	}

	.comment_img {
		width: 48px;
		height: 48px;
		border-radius: 50%;
	}

	.huifu {
		float: right;
		color: #ccc;
		display: block ruby
	}

	.huifu:hover {
		color: #409EFF
	}
</style>
